import { Avatar } from './Avatar.jsx'
import { StatusBadge } from './StatusBadge.jsx'

const ROLE_STYLE = {
  admin:   { bg: '#00e87a22', color: '#00e87a', border: '#00e87a33' },
  manager: { bg: '#00e87a22', color: '#00e87a', border: '#00e87a33' },
  engineer:{ bg: '#378add22', color: '#378add', border: '#378add33' },
  devops:  { bg: '#378add22', color: '#378add', border: '#378add33' },
  viewer:  { bg: '#44444422', color: '#888',    border: '#44444433' },
}

/**
 * @param {{
 *   member: {
 *     id: string, name: string, role: string, status: string,
 *     incidentsThisWeek?: number, lastActive?: string, email?: string
 *   },
 *   onClick?: () => void,
 *   onViewProfile?: () => void,
 * }} props
 */
export function TeamMemberRow({ member, onClick, onViewProfile }) {
  const roleKey = member.role?.toLowerCase() ?? 'viewer'
  const rs = ROLE_STYLE[roleKey] ?? ROLE_STYLE.viewer

  return (
    <tr
      onClick={onClick}
      className="border-b cursor-pointer transition-colors hover:bg-[#0d0d0d]"
      style={{ borderColor: '#1a1a1a' }}
    >
      <td className="py-2.5 pl-4 pr-2">
        <div className="flex items-center gap-2.5">
          <Avatar name={member.name} size={28} />
          <div className="flex flex-col">
            <span className="text-[12px] font-medium" style={{ color: '#f0f0f0' }}>{member.name}</span>
            <span className="text-[11px]" style={{ color: '#555' }}>{member.email}</span>
          </div>
        </div>
      </td>
      <td className="py-2.5 px-2">
        <span
          className="inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-semibold border"
          style={{ background: rs.bg, color: rs.color, borderColor: rs.border }}
        >
          {member.role}
        </span>
      </td>
      <td className="py-2.5 px-2">
        <StatusBadge status={member.status ?? 'offline'} />
      </td>
      <td className="py-2.5 px-2">
        <span className="text-[12px]" style={{ color: '#888' }}>{member.incidentsThisWeek ?? 0}</span>
      </td>
      <td className="py-2.5 px-2">
        <span className="text-[11px]" style={{ color: '#555' }}>{member.lastActive ?? '—'}</span>
      </td>
      <td className="py-2.5 pl-2 pr-4">
        <button
          onClick={(e) => { e.stopPropagation(); onViewProfile?.() }}
          className="text-[11px] px-2.5 py-1 rounded-md border transition-colors hover:border-[#2f2f2f]"
          style={{ background: '#111', borderColor: '#1f1f1f', color: '#888' }}
        >
          View profile
        </button>
      </td>
    </tr>
  )
}
