import { Avatar } from './Avatar.jsx'

const TYPE_COLOR = {
  update:     '#00e87a',
  escalation: '#ff4444',
  change:     '#f59e0b',
  ai:         '#7F77DD',
  note:       '#555',
}

/**
 * @param {{
 *   item: {
 *     type: string, timestamp: string, author?: string,
 *     content: string, isAi?: boolean
 *   },
 *   isLast?: boolean
 * }} props
 */
export function TimelineItem({ item, isLast = false }) {
  const color = TYPE_COLOR[item.type?.toLowerCase()] ?? '#555'
  const isAi = item.isAi || item.type?.toLowerCase() === 'ai'

  return (
    <div className="flex gap-3 relative">
      {/* vertical line */}
      {!isLast && (
        <span
          className="absolute left-[7px] top-6 bottom-0 w-px"
          style={{ background: '#1a1a1a' }}
        />
      )}

      {/* dot */}
      <span
        className="w-3.5 h-3.5 rounded-full mt-0.5 shrink-0 ring-2 ring-[#0d0d0d]"
        style={{ background: color }}
      />

      {/* content */}
      <div
        className={`flex-1 pb-4 rounded-lg p-3 ${isAi ? 'border' : ''}`}
        style={isAi ? { background: '#534AB722', borderColor: '#534AB744' } : {}}
      >
        <div className="flex items-center gap-2 mb-1">
          <span className="text-[10px]" style={{ color: '#555' }}>{item.timestamp}</span>
          {item.author && <Avatar name={item.author} size={16} />}
          {item.author && (
            <span className="text-[11px]" style={{ color: '#888' }}>{item.author}</span>
          )}
          {isAi && (
            <span
              className="text-[9px] font-bold px-1.5 py-0.5 rounded"
              style={{ background: '#534AB7', color: '#fff' }}
            >
              AI
            </span>
          )}
        </div>
        <p className="text-[13px] leading-relaxed" style={{ color: '#f0f0f0' }}>
          {item.content}
        </p>
      </div>
    </div>
  )
}
