/**
 * @param {{
 *   label: string,
 *   value: string | number,
 *   sublabel?: string,
 *   valueColor?: string,
 *   className?: string
 * }} props
 */
export function KpiCard({ label, value, sublabel, valueColor = '#f0f0f0', className = '' }) {
  return (
    <div
      className={`rounded-lg border p-3 flex flex-col gap-1 ${className}`}
      style={{ background: '#111', borderColor: '#1a1a1a' }}
    >
      <span className="text-[10px] uppercase tracking-wider" style={{ color: '#555' }}>
        {label}
      </span>
      <span className="text-lg font-semibold leading-tight" style={{ color: valueColor }}>
        {value}
      </span>
      {sublabel && (
        <span className="text-[10px]" style={{ color: '#555' }}>
          {sublabel}
        </span>
      )}
    </div>
  )
}
