import { useState } from 'react'

/**
 * @param {{
 *   summary?: string[],
 *   suggestions?: string[],
 *   generatedAt?: string,
 *   isLoading?: boolean,
 * }} props
 */
export function AiTriageCard({ summary = [], suggestions = [], generatedAt, isLoading = false }) {
  const [hoveredIdx, setHoveredIdx] = useState(null)

  return (
    <div
      className="rounded-lg border p-3 flex flex-col gap-3"
      style={{ background: '#0f0f1a', borderColor: '#534AB744' }}
    >
      {/* header */}
      <div className="flex items-center gap-2">
        <span
          className="text-[10px] font-bold px-1.5 py-0.5 rounded"
          style={{ background: '#534AB7', color: '#fff' }}
        >
          AI
        </span>
        <span className="text-[12px] font-medium" style={{ color: '#AFA9EC' }}>Instant triage</span>
      </div>

      {isLoading ? (
        <div className="flex flex-col gap-2">
          {[1, 2, 3].map((i) => (
            <div
              key={i}
              className="h-3 rounded animate-pulse"
              style={{ background: '#1a1a2e', width: i === 3 ? '60%' : '100%' }}
            />
          ))}
        </div>
      ) : (
        <>
          {/* summary bullets */}
          {summary.length > 0 && (
            <div className="flex flex-col gap-1.5">
              <span className="text-[10px] font-medium uppercase tracking-wider" style={{ color: '#534AB7' }}>
                Summary
              </span>
              {summary.map((point, i) => (
                <div key={i} className="flex items-start gap-2">
                  <span className="w-1 h-1 rounded-full mt-1.5 shrink-0" style={{ background: '#7F77DD' }} />
                  <p className="text-[12px] leading-relaxed" style={{ color: '#AFA9EC' }}>{point}</p>
                </div>
              ))}
            </div>
          )}

          {/* divider */}
          {suggestions.length > 0 && (
            <div className="border-t" style={{ borderColor: '#534AB733' }} />
          )}

          {/* suggestions */}
          {suggestions.length > 0 && (
            <div className="flex flex-col gap-2">
              <span className="text-[10px] font-medium uppercase tracking-wider" style={{ color: '#534AB7' }}>
                Suggestions
              </span>
              {suggestions.map((step, i) => (
                <div
                  key={i}
                  className="flex items-start gap-2 group relative"
                  onMouseEnter={() => setHoveredIdx(i)}
                  onMouseLeave={() => setHoveredIdx(null)}
                >
                  <span
                    className="w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold shrink-0 mt-0.5"
                    style={{ background: '#534AB722', color: '#7F77DD' }}
                  >
                    {i + 1}
                  </span>
                  <p className="text-[12px] leading-relaxed flex-1" style={{ color: '#AFA9EC' }}>{step}</p>
                  {hoveredIdx === i && (
                    <button
                      className="text-[10px] shrink-0"
                      style={{ color: '#7F77DD' }}
                    >
                      Use this →
                    </button>
                  )}
                </div>
              ))}
            </div>
          )}
        </>
      )}

      {/* footer */}
      <p className="text-[10px]" style={{ color: '#444' }}>
        Generated by AI{generatedAt ? ` · ${generatedAt}` : ''}
      </p>
    </div>
  )
}
