import { useState } from 'react'
import { NavLink } from 'react-router-dom'
import { Avatar } from './Avatar.jsx'

const NAV = [
  { to: '/dashboard',  label: 'Dashboard',  icon: GridIcon },
  { to: '/incidents',  label: 'Incidents',  icon: AlertIcon },
  { to: '/team',       label: 'Team',       icon: PeopleIcon },
  { to: '/messages',   label: 'Messages',   icon: ChatIcon },
  { to: '/reports',    label: 'Reports',    icon: DocIcon },
  { to: '/workspace',  label: 'Workspace',  icon: ToolsIcon },
]

export function AppSidebar({ user }) {
  const [expanded, setExpanded] = useState(false)
  const [locked, setLocked] = useState(false)

  const isOpen = expanded || locked

  return (
    <aside
      onMouseEnter={() => !locked && setExpanded(true)}
      onMouseLeave={() => !locked && setExpanded(false)}
      className="hidden md:flex flex-col shrink-0 transition-all duration-200 ease-in-out z-40"
      style={{
        width: isOpen ? 220 : 52,
        background: '#0d0d0d',
        borderRight: '0.5px solid #1a1a1a',
        minHeight: '100vh',
        position: 'sticky',
        top: 0,
      }}
    >
      {/* Logo */}
      <div className="flex items-center gap-2 px-3 py-3 h-12 border-b" style={{ borderColor: '#1a1a1a' }}>
        <span className="w-5 h-5 rounded-full bg-[#00e87a] shrink-0" />
        {isOpen && <span className="text-sm font-bold tracking-tight" style={{ color: '#f0f0f0' }}>Resolver</span>}
      </div>

      {/* Nav items */}
      <nav className="flex flex-col gap-0.5 px-2 py-3 flex-1">
        {NAV.map(({ to, label, icon: Icon }) => (
          <NavLink
            key={to}
            to={to}
            className={({ isActive }) =>
              `flex items-center gap-2.5 rounded-md px-2 py-2 text-[13px] font-medium transition-colors ${
                isActive ? 'text-[#00e87a]' : 'text-[#444] hover:text-[#888]'
              }`
            }
            style={({ isActive }) => isActive
              ? { background: '#00e87a18', borderLeft: '2px solid #00e87a' }
              : { borderLeft: '2px solid transparent' }
            }
          >
            <Icon size={16} />
            {isOpen && <span className="truncate">{label}</span>}
          </NavLink>
        ))}
      </nav>

      {/* Bottom */}
      <div className="px-2 py-3 flex flex-col gap-2 border-t" style={{ borderColor: '#1a1a1a' }}>
        <button
          onClick={() => setLocked((l) => !l)}
          className="flex items-center gap-2.5 rounded-md px-2 py-2 text-[13px] transition-colors text-[#444] hover:text-[#888]"
          title={locked ? 'Unlock sidebar' : 'Lock sidebar open'}
        >
          <SettingsIcon size={16} />
          {isOpen && <span>Settings</span>}
        </button>
        {user && (
          <div className="flex items-center gap-2 px-2">
            <Avatar name={user.name ?? 'User'} size={28} />
            {isOpen && (
              <span className="text-[11px] truncate" style={{ color: '#888' }}>{user.name}</span>
            )}
          </div>
        )}
      </div>
    </aside>
  )
}

/* ── icon primitives ── */
function GridIcon({ size = 16 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 16 16" fill="none">
      <rect x="1" y="1" width="6" height="6" rx="1" fill="currentColor" opacity=".6"/>
      <rect x="9" y="1" width="6" height="6" rx="1" fill="currentColor" opacity=".6"/>
      <rect x="1" y="9" width="6" height="6" rx="1" fill="currentColor" opacity=".6"/>
      <rect x="9" y="9" width="6" height="6" rx="1" fill="currentColor" opacity=".6"/>
    </svg>
  )
}

function AlertIcon({ size = 16 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 16 16" fill="none">
      <path d="M8 1L15 14H1L8 1Z" stroke="currentColor" strokeWidth="1.4" strokeLinejoin="round"/>
      <path d="M8 6V9" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/>
      <circle cx="8" cy="11.5" r="0.75" fill="currentColor"/>
    </svg>
  )
}

function PeopleIcon({ size = 16 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 16 16" fill="none">
      <circle cx="6" cy="5" r="2.5" stroke="currentColor" strokeWidth="1.3"/>
      <path d="M1 13c0-2.76 2.24-5 5-5s5 2.24 5 5" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/>
      <circle cx="12" cy="5" r="2" stroke="currentColor" strokeWidth="1.3"/>
      <path d="M15 13c0-2.21-1.34-4-3-4" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/>
    </svg>
  )
}

function ChatIcon({ size = 16 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 16 16" fill="none">
      <rect x="1" y="1" width="14" height="10" rx="2" stroke="currentColor" strokeWidth="1.3"/>
      <path d="M4 14l3-3h4" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round"/>
    </svg>
  )
}

function DocIcon({ size = 16 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 16 16" fill="none">
      <rect x="2" y="1" width="10" height="14" rx="1.5" stroke="currentColor" strokeWidth="1.3"/>
      <path d="M5 5h4M5 8h4M5 11h2" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/>
      <path d="M10 1v4h4" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round" strokeLinejoin="round"/>
      <path d="M10 1l4 4" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/>
    </svg>
  )
}

function ToolsIcon({ size = 16 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 16 16" fill="none">
      <path d="M10.5 2a3.5 3.5 0 00-3.4 4.3L2 11.5 2 14l2.5 0 5.2-5.1A3.5 3.5 0 1010.5 2z" stroke="currentColor" strokeWidth="1.3" strokeLinejoin="round"/>
    </svg>
  )
}

function SettingsIcon({ size = 16 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 16 16" fill="none">
      <circle cx="8" cy="8" r="2.5" stroke="currentColor" strokeWidth="1.3"/>
      <path d="M8 1v2M8 13v2M1 8h2M13 8h2M2.93 2.93l1.42 1.42M11.65 11.65l1.42 1.42M2.93 13.07l1.42-1.42M11.65 4.35l1.42-1.42" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/>
    </svg>
  )
}
