import { useState } from 'react'

/**
 * @param {{
 *   incidentId: string,
 *   initialProblem?: string,
 *   onGenerate?: (data: { problem: string, solution: string }) => Promise<any>,
 *   onPublish?: () => void,
 *   onSendToTeam?: () => void,
 * }} props
 */
export function PostmortemGenerator({ incidentId, initialProblem = '', onGenerate, onPublish, onSendToTeam }) {
  const [problem, setProblem] = useState(initialProblem)
  const [solution, setSolution] = useState('')
  const [loading, setLoading] = useState(false)
  const [generated, setGenerated] = useState(null)
  const [preview, setPreview] = useState(false)
  const [sendToTeam, setSendToTeam] = useState(false)
  const [publishPublic, setPublishPublic] = useState(false)

  async function handleGenerate() {
    setLoading(true)
    try {
      const result = await onGenerate?.({ problem, solution })
      setGenerated(result ?? {
        whatHappened: problem || 'An incident occurred affecting service availability.',
        rootCause: 'Root cause identified through system analysis.',
        solutionApplied: solution || 'Applied a targeted fix to resolve the issue.',
        preventionSteps: ['Add monitoring', 'Update runbook', 'Review alerts'],
      })
    } catch {
      /* error handled by parent */
    } finally {
      setLoading(false)
    }
  }

  return (
    <div
      className="rounded-lg border p-3 flex flex-col gap-3"
      style={{ background: '#0d0d0d', borderColor: '#1a1a1a' }}
    >
      <span className="text-[13px] font-medium" style={{ color: '#f0f0f0' }}>Generate postmortem</span>

      {!generated && (
        <span className="text-[11px]" style={{ color: '#555' }}>No draft generated yet</span>
      )}

      <div className="flex flex-col gap-2">
        <label className="text-[11px]" style={{ color: '#888' }}>Problem description</label>
        <textarea
          rows={3}
          value={problem}
          onChange={(e) => setProblem(e.target.value)}
          placeholder="Describe what happened..."
          className="w-full rounded-lg px-3 py-2 text-[12px] resize-none outline-none"
          style={{ background: '#111', border: '0.5px solid #1a1a1a', color: '#f0f0f0' }}
        />
      </div>

      <div className="flex flex-col gap-2">
        <label className="text-[11px]" style={{ color: '#888' }}>Solution applied</label>
        <textarea
          rows={3}
          value={solution}
          onChange={(e) => setSolution(e.target.value)}
          placeholder="What was done to resolve it..."
          className="w-full rounded-lg px-3 py-2 text-[12px] resize-none outline-none"
          style={{ background: '#111', border: '0.5px solid #1a1a1a', color: '#f0f0f0' }}
        />
      </div>

      <div className="flex gap-2">
        <button
          onClick={handleGenerate}
          disabled={loading}
          className="flex-1 py-1.5 rounded-md text-[12px] font-medium transition-opacity disabled:opacity-50"
          style={{ background: '#534AB7', color: '#fff' }}
        >
          {loading ? 'Generating…' : 'Generate with AI'}
        </button>
        {generated && (
          <button
            onClick={() => setPreview((v) => !v)}
            className="px-3 py-1.5 rounded-md text-[12px] border transition-colors"
            style={{ borderColor: '#1f1f1f', color: '#888' }}
          >
            {preview ? 'Hide' : 'Preview'}
          </button>
        )}
      </div>

      {/* Generated preview */}
      {generated && preview && (
        <div className="flex flex-col gap-2 border-t pt-3" style={{ borderColor: '#1a1a1a' }}>
          {[
            ['What happened', generated.whatHappened],
            ['Root cause', generated.rootCause],
            ['Solution applied', generated.solutionApplied],
          ].map(([label, text]) => (
            <details key={label} className="group">
              <summary
                className="text-[11px] font-medium cursor-pointer select-none"
                style={{ color: '#888' }}
              >
                {label}
              </summary>
              <p className="mt-1 text-[12px] leading-relaxed pl-2" style={{ color: '#f0f0f0' }}>
                {text}
              </p>
            </details>
          ))}
          {generated.preventionSteps?.length > 0 && (
            <details>
              <summary className="text-[11px] font-medium cursor-pointer" style={{ color: '#888' }}>
                Prevention steps
              </summary>
              <ol className="mt-1 pl-4 flex flex-col gap-0.5 list-decimal">
                {generated.preventionSteps.map((s, i) => (
                  <li key={i} className="text-[12px]" style={{ color: '#f0f0f0' }}>{s}</li>
                ))}
              </ol>
            </details>
          )}
        </div>
      )}

      {/* Send options */}
      {generated && (
        <div className="flex flex-col gap-2 border-t pt-3" style={{ borderColor: '#1a1a1a' }}>
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="checkbox"
              checked={sendToTeam}
              onChange={(e) => { setSendToTeam(e.target.checked); if (e.target.checked) onSendToTeam?.() }}
              className="rounded"
              style={{ accentColor: '#00e87a' }}
            />
            <span className="text-[12px]" style={{ color: '#888' }}>Send to team</span>
          </label>
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="checkbox"
              checked={publishPublic}
              onChange={(e) => { setPublishPublic(e.target.checked); if (e.target.checked) onPublish?.() }}
              className="rounded"
              style={{ accentColor: '#00e87a' }}
            />
            <span className="text-[12px]" style={{ color: '#888' }}>Publish publicly</span>
          </label>
          <button
            className="w-full py-1.5 rounded-md text-[12px] border transition-colors"
            style={{ borderColor: '#1f1f1f', color: '#888' }}
          >
            ↓ Download PDF
          </button>
        </div>
      )}
    </div>
  )
}
