import { useState } from 'react'
import { Avatar } from './Avatar.jsx'

/**
 * @param {{
 *   title: string,
 *   user?: { name: string },
 *   onSearch?: (v: string) => void,
 *   onCreateIncident?: () => void,
 *   notificationCount?: number,
 * }} props
 */
export function AppTopbar({ title, user, onSearch, onCreateIncident, notificationCount = 0 }) {
  const [q, setQ] = useState('')

  return (
    <header
      className="flex items-center gap-3 px-4 shrink-0 z-30"
      style={{
        height: 48,
        background: '#0d0d0d',
        borderBottom: '0.5px solid #1a1a1a',
        position: 'sticky',
        top: 0,
      }}
    >
      {/* Title */}
      <span className="text-[13px] font-medium shrink-0" style={{ color: '#f0f0f0' }}>
        {title}
      </span>

      {/* Search */}
      <div className="flex-1 max-w-[220px]">
        <input
          value={q}
          onChange={(e) => { setQ(e.target.value); onSearch?.(e.target.value) }}
          placeholder="Search incidents..."
          className="w-full h-7 px-2.5 text-[12px] rounded-md outline-none"
          style={{
            background: '#111',
            border: '0.5px solid #1f1f1f',
            color: '#f0f0f0',
          }}
        />
      </div>

      <div className="flex-1" />

      {/* Action icons */}
      <div className="flex items-center gap-1.5">
        <TopbarBtn onClick={onCreateIncident} title="New incident">
          <PlusIcon />
        </TopbarBtn>

        <TopbarBtn title="Filter">
          <FilterIcon />
        </TopbarBtn>

        <TopbarBtn title="Export">
          <DownloadIcon />
        </TopbarBtn>

        <TopbarBtn title="Notifications" className="relative">
          <BellIcon />
          {notificationCount > 0 && (
            <span
              className="absolute top-0.5 right-0.5 w-1.5 h-1.5 rounded-full"
              style={{ background: '#ff4444' }}
            />
          )}
        </TopbarBtn>

        {user && (
          <Avatar name={user.name} size={28} className="ml-1" />
        )}
      </div>
    </header>
  )
}

function TopbarBtn({ children, className = '', ...props }) {
  return (
    <button
      type="button"
      className={`relative flex items-center justify-center w-7 h-7 rounded-md transition-colors hover:bg-[#1a1a1a] ${className}`}
      style={{ background: '#111', border: '0.5px solid #1f1f1f', color: '#888' }}
      {...props}
    >
      {children}
    </button>
  )
}

function PlusIcon() {
  return <svg width="14" height="14" viewBox="0 0 14 14" fill="none"><path d="M7 2v10M2 7h10" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/></svg>
}
function FilterIcon() {
  return <svg width="14" height="14" viewBox="0 0 14 14" fill="none"><path d="M2 3h10M4 7h6M6 11h2" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/></svg>
}
function DownloadIcon() {
  return <svg width="14" height="14" viewBox="0 0 14 14" fill="none"><path d="M7 2v7M4.5 6.5L7 9l2.5-2.5" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round"/><path d="M2 11h10" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round"/></svg>
}
function BellIcon() {
  return <svg width="14" height="14" viewBox="0 0 14 14" fill="none"><path d="M7 1.5a4 4 0 00-4 4v2.5l-1 1.5h10l-1-1.5V5.5a4 4 0 00-4-4z" stroke="currentColor" strokeWidth="1.3"/><path d="M5.5 10.5a1.5 1.5 0 003 0" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/></svg>
}
