import { StatusBadge } from './StatusBadge.jsx'

/**
 * @param {{
 *   report: {
 *     id: string, title: string, status: string, date: string,
 *     services?: string[], duration?: string, summary?: string
 *   },
 *   onClick?: () => void,
 * }} props
 */
export function PublicReportCard({ report, onClick }) {
  return (
    <div
      onClick={onClick}
      className="rounded-xl border p-4 cursor-pointer transition-colors hover:border-[#2f2f2f] flex flex-col gap-2"
      style={{ background: '#0d0d0d', borderColor: '#1a1a1a' }}
    >
      {/* top row */}
      <div className="flex items-center justify-between">
        <StatusBadge status={report.status ?? 'published'} />
        <span className="text-[11px]" style={{ color: '#555' }}>{report.date}</span>
      </div>

      {/* title */}
      <h3 className="text-[14px] font-medium" style={{ color: '#f0f0f0' }}>{report.title}</h3>

      {/* services */}
      {report.services?.length > 0 && (
        <div className="flex flex-wrap gap-1">
          {report.services.map((s) => (
            <span
              key={s}
              className="text-[10px] px-2 py-0.5 rounded-full"
              style={{ background: '#141414', color: '#888' }}
            >
              {s}
            </span>
          ))}
        </div>
      )}

      {/* duration */}
      {report.duration && (
        <span className="text-[11px]" style={{ color: '#555' }}>Duration: {report.duration}</span>
      )}

      {/* summary */}
      {report.summary && (
        <p
          className="text-[12px] leading-relaxed overflow-hidden"
          style={{ color: '#888', display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical' }}
        >
          {report.summary}
        </p>
      )}

      {/* footer */}
      <div className="flex items-center justify-between pt-1">
        <span className="text-[12px] font-medium" style={{ color: '#00e87a' }}>
          Read full report →
        </span>
        <button
          onClick={(e) => e.stopPropagation()}
          className="text-[11px] px-2 py-0.5 rounded-md border transition-colors hover:border-[#2f2f2f]"
          style={{ background: '#111', borderColor: '#1f1f1f', color: '#888' }}
          title="Download PDF"
        >
          ↓ PDF
        </button>
      </div>
    </div>
  )
}
